  readonly sessionId: string;
  send(message: string | SDKUserMessage): Promise<void>;
  stream(): AsyncGenerator<SDKMessage, void>;
  close(): void;
}
```


## [вҖӢ](https://code.claude.com/docs/zh-TW/agent-sdk/typescript-v2-preview#%E5%8A%9F%E8%83%BD%E5%8F%AF%E7%94%A8%E6%80%A7) еҠҹиғҪеҸҜз”ЁжҖ§


